<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">tailscale</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> funnel</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --bg</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --set-path</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /googlechat</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://127.0.0.1:18789/googlechat</span></span>
